hooks.command:
python -c "
import json, sys
sys.stderr.reconfigure(encoding='utf-8')
try: data = json.load(sys.stdin)
except Exception: sys.exit(0)
if data.get('tool_name','') != 'mcp__vivado__generate_bitstream': sys.exit(0)
sys.stderr.write('[bitstream-guard] 烧板前建议先调用 mcp__vivado__check_bitstream_readiness 确认 READY,避免时序违例/未布线状态下生成无效比特流。'+chr(10))
sys.exit(2)
"

python -c "
import json, sys
sys.stderr.reconfigure(encoding='utf-8')
try: data = json.load(sys.stdin)
except Exception: sys.exit(0)
fp = data.get('tool_input', {}).get('file_path') or data.get('tool_response', {}).get('filePath') or ''
if not fp.lower().endswith('.xdc'): sys.exit(0)
from vivado_mcp.analysis.xdc_linter import lint_xdc_files, format_lint_report
r = lint_xdc_files([fp])
if r.issues:
    sys.stderr.write('[xdc-lint hook] ' + format_lint_report(r) + chr(10))
    sys.exit(2)
"
